import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Signup.css"; 

function Signup() {
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    username: "",
    password: "",
    confirmPassword: "",
    mobileNumber: "",
    role: "Freelancer" // Default Role
  });
  
  const [errors, setErrors] = useState({});
  const [submitError, setSubmitError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
    if (errors[name]) setErrors({ ...errors, [name]: "" });
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formData.fullName.trim()) newErrors.fullName = "Full Name is required";
    if (!/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = "Invalid email format";
    if (formData.password.length < 6) newErrors.password = "Password must be 6+ chars";
    if (formData.password !== formData.confirmPassword) newErrors.confirmPassword = "Passwords do not match";
    if (formData.mobileNumber.length !== 10) newErrors.mobileNumber = "Enter 10 digit mobile";
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsLoading(true);
    setSubmitError("");

    try {
      const response = await fetch('http://localhost:3000/api/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok) {
        alert("Account Created! Please Login.");
        navigate("/login");
      } else {
        setSubmitError(data.msg || "Signup failed");
      }
    } catch (error) {
      setSubmitError("Server connection error. Check backend port 3000.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="signup-overlay">
      <div className="signup-popup">
        <h2 className="signup-title">Create Account</h2>
        <p className="signup-subtitle">Join Student Freelancer Marketplace</p>

        {submitError && <div className="signup-error-box">{submitError}</div>}

        <form onSubmit={handleSubmit} className="signup-form">
          <div className="input-row">
            <select name="role" value={formData.role} onChange={handleChange} className="signup-input">
              <option value="Freelancer">I am a Freelancer</option>
              <option value="Client">I want to Hire</option>
            </select>
          </div>

          <input type="text" name="fullName" placeholder="Full Name" value={formData.fullName} onChange={handleChange} className="signup-input" />
          {errors.fullName && <span className="err-txt">{errors.fullName}</span>}

          <input type="email" name="email" placeholder="Email Address" value={formData.email} onChange={handleChange} className="signup-input" />
          {errors.email && <span className="err-txt">{errors.email}</span>}

          <div className="input-row-flex">
            <input type="text" name="username" placeholder="Username" value={formData.username} onChange={handleChange} className="signup-input" />
            <input type="text" name="mobileNumber" placeholder="Mobile No" value={formData.mobileNumber} onChange={handleChange} className="signup-input" />
          </div>

          <div className="input-row-flex">
            <input type="password" name="password" placeholder="Password" value={formData.password} onChange={handleChange} className="signup-input" />
            <input type="password" name="confirmPassword" placeholder="Confirm Password" value={formData.confirmPassword} onChange={handleChange} className="signup-input" />
          </div>
          {errors.confirmPassword && <span className="err-txt">{errors.confirmPassword}</span>}

          <button type="submit" className="signup-submit-btn" disabled={isLoading}>
            {isLoading ? <span className="spinner"></span> : "Register Now"}
          </button>
        </form>

        <p className="signup-switch">Already have an account? <span onClick={() => navigate("/login")}>Login</span></p>
      </div>
    </div>
  );
}

export default Signup;
